namespace sv_0ce771007e614ca4ad3070a316678600.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings

<nav class="settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
            <span class="sidebar-icon">@GetIcon(section)</span>
            <span class="sidebar-label">@section</span>
        </button>
    }
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p>Loading profile...</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-preview">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
                <p class="avatar-url-display">@_avatarUrl</p>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" @bind="_bio" rows="4"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardChanges">Discard Changes</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Profile saved successfully!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _showSuccess = true;
        _ = HideToastAfterDelay();
    }

    private async Task HideToastAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }
}

@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Notifications</h2>

    @if (_loading)
    {
        <p>Loading notification preferences...</p>
    }
    else
    {
        <div class="notification-form">
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_emailNotifications" />
                    <span>Email Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_pushNotifications" />
                    <span>Push Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_weeklyDigest" />
                    <span>Weekly Digest</span>
                </label>
            </div>

            <h3>Muted Channels</h3>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="(e) => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <span>@channel</span>
                    </label>
                }
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Preferences saved!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();

    private static readonly string[] _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _showSuccess = true;
        _ = HideToastAfterDelay();
    }

    private async Task HideToastAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="expandable-panel">
    <button class="panel-header" @onclick="() => _expanded = !_expanded">
        <span>Change Password</span>
        <span class="expand-icon">@(_expanded ? "▾" : "▸")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" @bind="_currentPassword" />
            </div>

            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" @bind="_newPassword" />
            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="toast toast-error">@_error</div>
            }
            @if (_showSuccess)
            {
                <div class="toast toast-success">Password updated successfully!</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync">Update Password</button>
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _showSuccess;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _showSuccess = true;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services

<div class="sessions-section">
    <h3>Active Sessions</h3>

    <table class="sessions-table">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@session.LastActive.ToString("g")</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-danger btn-sm"
                                    @onclick="() => PromptRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="current-session-badge">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (_sessionToRevoke is not null)
    {
        <div class="confirmation-dialog-overlay">
            <div class="confirmation-dialog">
                <p>Revoke session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                <div class="dialog-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Confirm</button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Security</h2>

    @if (_loading)
    {
        <p>Loading security settings...</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="two-factor-section">
            <h3>Two-Factor Authentication</h3>
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" checked="@_twoFactorEnabled" disabled />
                    <span>Two-Factor Authentication</span>
                    <span class="status-indicator @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </label>
            </div>

            @if (_lastPasswordChange.HasValue)
            {
                <p class="last-change-info">Last password change: @_lastPasswordChange.Value.ToString("f")</p>
            }
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevoke="RevokeSessionAsync" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string _currentSessionId = "";

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        // Assume the first session is the current one
        _currentSessionId = _sessions.FirstOrDefault()?.Id ?? "";
        _loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions.RemoveAll(s => s.Id == sessionId);
    }
}

