            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@session.LastActive.ToString("g")</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-danger btn-sm"
                                    @onclick="() => PromptRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="current-session-badge">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (_sessionToRevoke is not null)
    {
        <div class="confirmation-dialog-overlay">
            <div class="confirmation-dialog">
                <p>Revoke session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                <div class="dialog-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Confirm</button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

