    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _showSuccess = true;
        _ = HideToastAfterDelay();
    }

    private async Task HideToastAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
"}

{"path": "/tmp/sv-0ce771007e614ca4ad3070a316678600/Components/Pages/Settings/ChangePasswordPanel.razor", "file_text": "@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="expandable-panel">
    <button class="panel-header" @onclick="() => _expanded = !_expanded">
        <span>Change Password</span>
        <span class="expand-icon">@(_expanded ? "▾" : "▸")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" @bind="_currentPassword" />
            </div>

            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" @bind="_newPassword" />
            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="toast toast-error">@_error</div>
            }
            @if (_showSuccess)
            {
                <div class="toast toast-success">Password updated successfully!</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync">Update Password</button>
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _showSuccess;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _showSuccess = true;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}
"}

{"path": "/tmp/sv-0ce771007e614ca4ad3070a316678600/Components/Pages/Settings/ActiveSessionsTable.razor", "file_text": "@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services

<div class="sessions-section">
    <h3>Active Sessions</h3>

    <table class="sessions-table">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@session.LastActive.ToString("g")</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-danger btn-sm"
                                    @onclick="() => PromptRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="current-session-badge">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (_sessionToRevoke is not null)
    {
        <div class="confirmation-dialog-overlay">
            <div class="confirmation-dialog">
                <p>Revoke session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                <div class="dialog-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Confirm</button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}
"}

{"path": "/tmp/sv-0ce771007e614ca4ad3070a316678600/Components/Pages/Settings/SecuritySection.razor", "file_text": "@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Security</h2>

    @if (_loading)
    {
        <p>Loading security settings...</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="two-factor-section">
            <h3>Two-Factor Authentication</h3>
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" checked="@_twoFactorEnabled" disabled />
                    <span>Two-Factor Authentication</span>
                    <span class="status-indicator @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </label>
            </div>

            @if (_lastPasswordChange.HasValue)
            {
                <p class="last-change-info">Last password change: @_lastPasswordChange.Value.ToString("f")</p>
            }
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevoke="RevokeSessionAsync" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string _currentSessionId = "";

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        // Assume the first session is the current one
        _currentSessionId = _sessions.FirstOrDefault()?.Id ?? "";
        _loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions.RemoveAll(s => s.Id == sessionId);
    }
}
"}

{"path": "/tmp/sv-0ce771007e614ca4ad3070a316678600/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Appearance</h2>

    @if (_loading)
    {
        <p>Loading appearance settings...</p>
    }
    else
    {
        <div class="appearance-form">
            <div class="form-group">
                <label>Theme</label>
                <div class="radio-group">
                    <label><input type="radio" name="theme" value="Light" @onchange="() => _theme = &quot;Light&quot;" checked="@(_theme == "Light")" /> Light</label>
                    <label><input type="radio" name="theme" value="Dark" @onchange="() => _theme = &quot;Dark&quot;" checked="@(_theme == "Dark")" /> Dark</label>
                    <label><input type="radio" name="theme" value="System" @onchange="() => _theme = &quot;System&quot;" checked="@(_theme == "System")" /> System</label>
                </div>
            </div>

            <div class="form-group">
                <label>Font Size</label>
                <div class="radio-group">
                    <label><input type="radio" name="fontSize" value="Small" @onchange="() => _fontSize = &quot;Small&quot;" checked="@(_fontSize == "Small")" /> Small</label>
                    <label><input type="radio" name="fontSize" value="Medium" @onchange="() => _fontSize = &quot;Medium&quot;" checked="@(_fontSize == "Medium")" /> Medium</label>
                    <label><input type="radio" name="fontSize" value="Large" @onchange="() => _fontSize = &quot;Large&quot;" checked="@(_fontSize == "Large")" /> Large</label>
                </div>
            </div>

            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_language">
                    <option value="en">English</option>
                    <option value="es">Spanish</option>
                    <option value="fr">French</option>
                    <option value="de">German</option>
                    <option value="ja">Japanese</option>
                    <option value="zh">Chinese</option>
                </select>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_compactMode" />
                    <span>Compact Mode</span>
                </label>
            </div>

            <div class="appearance-preview @GetPreviewClasses()">
                <h4>Preview</h4>
                <p class="preview-text">This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <span class="preview-heading">Sample Card</span>
                    <span class="preview-body">Card body text appears here.</span>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Appearance settings saved!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = _theme.ToLowerInvariant();
        var size = _fontSize.ToLowerInvariant();
        var compact = _compactMode ? "compact" : "";
        return $"preview-{theme} preview-{size} {compact}".Trim();
    }

    private async Task SaveAsync()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _showSuccess = true;
        _ = HideToastAfterDelay();
    }

    private async Task HideToastAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
"}

