@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings

<nav class="settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
            <span class="sidebar-icon">@GetIcon(section)</span>
            <span class="sidebar-label">@section</span>
        </button>
    }
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p>Loading profile...</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-preview">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
                <p class="avatar-url-display">@_avatarUrl</p>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" @bind="_bio" rows="4"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardChanges">Discard Changes</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Profile saved successfully!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _showSuccess = true;
        _ = HideToastAfterDelay();
    }

    private async Task HideToastAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }
}

