@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@using sv_0ce771007e614ca4ad3070a316678600.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Appearance</h2>

    @if (_loading)
    {
        <p>Loading appearance settings...</p>
    }
    else
    {
        <div class="appearance-form">
            <div class="form-group">
                <label>Theme</label>
                <div class="radio-group">
                    <label><input type="radio" name="theme" value="Light" @onchange="() => _theme = &quot;Light&quot;" checked="@(_theme == "Light")" /> Light</label>
                    <label><input type="radio" name="theme" value="Dark" @onchange="() => _theme = &quot;Dark&quot;" checked="@(_theme == "Dark")" /> Dark</label>
                    <label><input type="radio" name="theme" value="System" @onchange="() => _theme = &quot;System&quot;" checked="@(_theme == "System")" /> System</label>
                </div>
            </div>

            <div class="form-group">
                <label>Font Size</label>
                <div class="radio-group">
                    <label><input type="radio" name="fontSize" value="Small" @onchange="() => _fontSize = &quot;Small&quot;" checked="@(_fontSize == "Small")" /> Small</label>
                    <label><input type="radio" name="fontSize" value="Medium" @onchange="() => _fontSize = &quot;Medium&quot;" checked="@(_fontSize == "Medium")" /> Medium</label>
                    <label><input type="radio" name="fontSize" value="Large" @onchange="() => _fontSize = &quot;Large&quot;" checked="@(_fontSize == "Large")" /> Large</label>
                </div>
            </div>

            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_language">
                    <option value="en">English</option>
                    <option value="es">Spanish</option>
                    <option value="fr">French</option>
                    <option value="de">German</option>
                    <option value="ja">Japanese</option>
                    <option value="zh">Chinese</option>
                </select>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_compactMode" />
                    <span>Compact Mode</span>
                </label>
            </div>

            <div class="appearance-preview @GetPreviewClasses()">
                <h4>Preview</h4>
                <p class="preview-text">This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <span class="preview-heading">Sample Card</span>
                    <span class="preview-body">Card body text appears here.</span>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Appearance settings saved!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = _theme.ToLowerInvariant();
        var size = _fontSize.ToLowerInvariant();
        var compact = _compactMode ? "compact" : "";
        return $"preview-{theme} preview-{size} {compact}".Trim();
    }

    private async Task SaveAsync()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _showSuccess = true;
        _ = HideToastAfterDelay();
    }

    private async Task HideToastAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

