+@using sv_0ce771007e614ca4ad3070a316678600.Services
+@inject ISettingsService SettingsService
+
+<div class="settings-section">
+    <h2>Appearance</h2>
+
+    @if (_loading)
+    {
+        <p>Loading appearance settings...</p>
+    }
+    else
+    {
+        <div class="appearance-form">
+            <div class="form-group">
+                <label>Theme</label>
+                <div class="radio-group">
+                    <label><input type="radio" name="theme" value="Light" @onchange="() => _theme = &quot;Light&quot;" checked="@(_theme == "Light")" /> Light</label>
+                    <label><input type="radio" name="theme" value="Dark" @onchange="() => _theme = &quot;Dark&quot;" checked="@(_theme == "Dark")" /> Dark</label>
+                    <label><input type="radio" name="theme" value="System" @onchange="() => _theme = &quot;System&quot;" checked="@(_theme == "System")" /> System</label>
+                </div>
+            </div>
+
+            <div class="form-group">
+                <label>Font Size</label>
+                <div class="radio-group">
+                    <label><input type="radio" name="fontSize" value="Small" @onchange="() => _fontSize = &quot;Small&quot;" checked="@(_fontSize == "Small")" /> Small</label>
+                    <label><input type="radio" name="fontSize" value="Medium" @onchange="() => _fontSize = &quot;Medium&quot;" checked="@(_fontSize == "Medium")" /> Medium</label>
+                    <label><input type="radio" name="fontSize" value="Large" @onchange="() => _fontSize = &quot;Large&quot;" checked="@(_fontSize == "Large")" /> Large</label>
+                </div>
+            </div>
+
+            <div class="form-group">
+                <label for="language">Language</label>
+                <select id="language" @bind="_language">
+                    <option value="en">English</option>
+                    <option value="es">Spanish</option>
+                    <option value="fr">French</option>
+                    <option value="de">German</option>
+                    <option value="ja">Japanese</option>
+                    <option value="zh">Chinese</option>
+                </select>
+            </div>
+
+            <div class="toggle-group">
+                <label class="toggle-label">
+                    <input type="checkbox" @bind="_compactMode" />
+                    <span>Compact Mode</span>
+                </label>
+            </div>
+
+            <div class="appearance-preview @GetPreviewClasses()">
+                <h4>Preview</h4>
+                <p class="preview-text">This is how your content will look with the selected settings.</p>
+                <div class="preview-card">
+                    <span class="preview-heading">Sample Card</span>
+                    <span class="preview-body">Card body text appears here.</span>
+                </div>
+            </div>
+
+            <div class="form-actions">
+                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
+            </div>
+
+            @if (_showSuccess)
+            {
+                <div class="toast toast-success">Appearance settings saved!</div>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    private bool _loading = true;
+    private bool _showSuccess;
+    private string _theme = "System";
+    private string _fontSize = "Medium";
+    private string _language = "en";
+    private bool _compactMode;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _loading = true;
+        var settings = await SettingsService.GetAppearanceAsync();
+        _theme = settings.Theme;
+        _fontSize = settings.FontSize;
+        _language = settings.Language;
+        _compactMode = settings.CompactMode;
+        _loading = false;
+    }
+
+    private string GetPreviewClasses()
+    {
+        var theme = _theme.ToLowerInvariant();
+        var size = _fontSize.ToLowerInvariant();
+        var compact = _compactMode ? "compact" : "";
+        return $"preview-{theme} preview-{size} {compact}".Trim();
+    }
+
+    private async Task SaveAsync()
+    {
+        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+        await SettingsService.SaveAppearanceAsync(settings);
+        _showSuccess = true;
+        _ = HideToastAfterDelay();
+    }
+
+    private async Task HideToastAfterDelay()
+    {
+        await Task.Delay(3000);
+        _showSuccess = false;
+        await InvokeAsync(StateHasChanged);
+    }
+}
+

toolArgs.file_text:
@page "/settings"
@namespace sv_0ce771007e614ca4ad3070a316678600.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-dashboard {
    display: flex;
    min-height: 100vh;
    gap: 0;
}

/* Sidebar */
::deep .settings-sidebar {
    display: flex;
    flex-direction: column;
    width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #e0e0e0;
    padding: 1rem 0;
}

::deep .sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.5rem;
    border: none;
    background: transparent;
    cursor: pointer;
    font-size: 0.95rem;
    color: #555;
    text-align: left;
    width: 100%;
    transition: background 0.15s, color 0.15s;
}

::deep .sidebar-item:hover {
    background: #e9ecef;
    color: #333;
}

::deep .sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

::deep .sidebar-icon {
    font-size: 1.1rem;
}

/* Main content */
.settings-content {
    flex: 1;
    padding: 2rem 3rem;
    max-width: 800px;
}

/* Section headings */
::deep .settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    border-bottom: 1px solid #e0e0e0;
    padding-bottom: 0.5rem;
}

::deep .settings-section h3 {
    margin-top: 1.5rem;
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

/* Form groups */
::deep .form-group {
    margin-bottom: 1rem;
}

::deep .form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.3rem;
    font-size: 0.9rem;
}

::deep .form-group input[type="text"],
::deep .form-group input[type="email"],
::deep .form-group input[type="password"],
::deep .form-group textarea,
::deep .form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .form-group textarea {
    resize: vertical;
}

/* Buttons */
::deep .btn {
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    transition: opacity 0.15s;
}

::deep .btn:hover {
    opacity: 0.85;
}

::deep .btn-primary {
    background: #0d6efd;
    color: #fff;
}

::deep .btn-secondary {
    background: #6c757d;
    color: #fff;
}

::deep .btn-danger {
    background: #dc3545;
    color: #fff;
}

::deep .btn-sm {
    padding: 0.3rem 0.75rem;
    font-size: 0.8rem;
}

::deep .form-actions {
    margin-top: 1.5rem;
    display: flex;
    gap: 0.75rem;
}

/* Toast messages */
::deep .toast {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 4px;
    font-size: 0.9rem;
}

::deep .toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

::deep .toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

/* Toggle groups */
::deep .toggle-group {
    margin-bottom: 0.75rem;
}

::deep .toggle-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
    font-size: 0.95rem;
}

::deep .toggle-label input[type="checkbox"] {
    width: 1.1rem;
    height: 1.1rem;
}

/* Channel list */
::deep .channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding-left: 0.25rem;
}

::deep .channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.9rem;
    cursor: pointer;
}

/* Avatar */
::deep .avatar-preview {
    margin-bottom: 1.5rem;
    display: flex;
    align-items: center;
    gap: 1rem;
}

::deep .avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #e0e0e0;
}

::deep .avatar-url-display {
    font-size: 0.8rem;
    color: #666;
    word-break: break-all;
}

/* Expandable panel */
::deep .expandable-panel {
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    margin-bottom: 1.5rem;
}

::deep .panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 600;
}

::deep .panel-body {
    padding: 1rem;
    border-top: 1px solid #e0e0e0;
}

/* Two-factor */
::deep .status-indicator {
    margin-left: 0.5rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
}

::deep .status-on {
    background: #d1e7dd;
    color: #0f5132;
}

::deep .status-off {
    background: #f8d7da;
    color: #842029;
}

::deep .last-change-info {
    font-size: 0.85rem;
    color: #666;
    margin-top: 0.5rem;
}

/* Sessions table */
::deep .sessions-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0.75rem;
}

::deep .sessions-table th,
::deep .sessions-table td {
    padding: 0.6rem 0.75rem;
    text-align: left;
    border-bottom: 1px solid #e0e0e0;
    font-size: 0.9rem;
}

::deep .sessions-table th {
    background: #f8f9fa;
    font-weight: 600;
}

::deep .current-session-badge {
    font-size: 0.8rem;
    color: #0d6efd;
    font-weight: 600;
}

/* Confirmation dialog */
::deep .confirmation-dialog-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

::deep .confirmation-dialog {
    background: #fff;
    padding: 1.5rem 2rem;
    border-radius: 8px;
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
    max-width: 400px;
}

::deep .dialog-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1rem;
}

/* Radio group */
::deep .radio-group {
    display: flex;
    gap: 1.25rem;
    margin-top: 0.25rem;
}

::deep .radio-group label {
    display: flex;
    align-items: center;
    gap: 0.3rem;
    font-weight: normal;
    cursor: pointer;
}

/* Appearance preview */
::deep .appearance-preview {
    margin-top: 1.5rem;
    padding: 1.5rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    transition: all 0.2s;
}

::deep .appearance-preview h4 {
    margin-top: 0;
    margin-bottom: 0.75rem;
}

::deep .preview-card {
    background: #f0f0f0;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-top: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
}

::deep .preview-heading {
    font-weight: 600;
}

::deep .preview-body {
    font-size: 0.9em;
    color: #555;
}

/* Preview theme variants */
::deep .preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}

::deep .preview-dark .preview-card {
    background: #2d2d2d;
}

::deep .preview-dark .preview-body {
    color: #aaa;
}

::deep .preview-light {
    background: #fff;
    color: #333;
}

::deep .preview-system {
    background: #fafafa;
    color: #333;
}

/* Preview font sizes */
::deep .preview-small {
    font-size: 0.8rem;
}

::deep .preview-medium {
    font-size: 1rem;
}

::deep .preview-large {
    font-size: 1.2rem;
}

/* Preview compact */
::deep .compact {
    padding: 0.75rem;
}

::deep .compact .preview-card {
    padding: 0.4rem 0.75rem;
}

