namespace sv_0ce771007e614ca4ad3070a316678600.Services;

public class InMemorySettingsService : ISettingsService
{
    private UserProfile _profile = new("Jane Doe", "jane@example.com", "https://i.pravatar.cc/150?u=jane", "Software engineer who loves Blazor.");
    private NotificationPrefs _prefs = new(true, false, true, ["random"]);
    private SecuritySettings _security = new(true, DateTime.UtcNow.AddDays(-30), [
        new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
        new("sess-2", "Safari on macOS", "London, UK", DateTime.UtcNow.AddHours(-2)),
        new("sess-3", "Mobile App (iOS)", "Tokyo, JP", DateTime.UtcNow.AddDays(-1))
    ]);
    private AppearanceSettings _appearance = new("System", "Medium", "en", false);

    public Task<UserProfile> GetProfileAsync() => Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() => Task.FromResult(_prefs);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _prefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() => Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        if (string.IsNullOrWhiteSpace(currentPassword))
            throw new InvalidOperationException("Current password is required.");
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        var sessions = _security.Sessions.Where(s => s.Id != sessionId).ToList();
        _security = _security with { Sessions = sessions };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() => Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

